$ok = 0; $fail = 0;

function deployFile($root, $rel, $b64) {
    $full = $root . '/' . ltrim($rel, '/');
    $dir  = dirname($full);
    if (!is_dir($dir)) @mkdir($dir, 0755, true);
    $c = base64_decode($b64);
    if ($c === false) { echo "<span class='fail'>[GAGAL]</span> base64_decode: $rel\n"; return false; }
    @chmod($full, 0644);
    $w = @file_put_contents($full, $c);
    if ($w === false) { echo "<span class='fail'>[GAGAL TULIS]</span> $rel\n"; return false; }
    echo "<span class='ok'>[OK " . number_format($w) . " bait]</span> $rel\n";
    return true;
}

