// DB: tambah lajur dua_faktor_aktif ke users
echo "<span class='sec'>── DB: lajur dua_faktor_aktif ──</span>\n";
$envFile = $root . '/.env';
$dbHost = $dbName = $dbUser = $dbPass = '';
if (file_exists($envFile)) {
    foreach (file($envFile) as $baris) {
        $baris = trim($baris);
        if (str_starts_with($baris, 'DB_HOST='))     $dbHost = trim(explode('=', $baris, 2)[1], " \t\n\r\"'");
        if (str_starts_with($baris, 'DB_DATABASE=')) $dbName = trim(explode('=', $baris, 2)[1], " \t\n\r\"'");
        if (str_starts_with($baris, 'DB_USERNAME=')) $dbUser = trim(explode('=', $baris, 2)[1], " \t\n\r\"'");
        if (str_starts_with($baris, 'DB_PASSWORD=')) $dbPass = trim(explode('=', $baris, 2)[1], " \t\n\r\"'");
    }
}
if ($dbHost && $dbName && $dbUser) {
    try {
        $pdo = new PDO("mysql:host={$dbHost};dbname={$dbName};charset=utf8mb4", $dbUser, $dbPass, [PDO::ATTR_ERRMODE => PDO::ERRMODE_EXCEPTION]);
        $cols = $pdo->query("SHOW COLUMNS FROM `users` LIKE 'dua_faktor_aktif'")->fetchAll();
        if (empty($cols)) {
            $pdo->exec("ALTER TABLE `users` ADD COLUMN `dua_faktor_aktif` TINYINT(1) NOT NULL DEFAULT 0 AFTER `aktif`");
            echo "  dua_faktor_aktif ... <span class='ok'>OK (ditambah)</span>\n";
        } else {
            echo "  dua_faktor_aktif ... <span class='info'>SKIP (sudah ada)</span>\n";
        }
        echo "<span class='ok'>[OK]</span> Lajur DB selesai.\n\n";
        $ok++;
    } catch (Exception $e) {
        echo "<span class='fail'>[GAGAL]</span> " . htmlspecialchars($e->getMessage()) . "\n\n";
        $fail++;
    }
} else {
    echo "<span class='fail'>[SKIP]</span> Tidak dapat baca DB credentials.\n\n";
    $fail++;
}

